function Item({ label }) {
  const [text, setText] = useState('');
  return <div><span>{label}</span><input value={text} onChange={e => setText(e.target.value)} /></div>;
}
function App() {
  const [items, setItems] = useState(['A','B','C']);
  return <div>
    <button onClick={() => setItems(['NEW', ...items])}>头部插入</button>
    {items.map((item, i) => <Item key={i} label={item} />)}
    // 对比: <Item key={item} label={item} />
  </div>;
}
